const sessions = new Map();

// Default session lifetime: 24 hours.
const SESSION_TTL_MS = 24 * 60 * 60 * 1000;

/**
 * Create a new session record for the given user and store it.
 *
 * @param {string} userId - Identifier of the user the session belongs to.
 * @returns {{id: string, userId: string, createdAt: Date, expiresAt: Date}} The new session record.
 */
function createSession(userId) {
  if (!userId) {
    throw new Error('createSession: userId is required');
  }

  const createdAt = new Date();
  const session = {
    id: randomUUID(),
    userId,
    createdAt,
    expiresAt: new Date(createdAt.getTime() + SESSION_TTL_MS),
  };

  sessions.set(session.id, session);
  return session;
}

module.exports = { createSession, sessions };
